class InventoryCatalog:
    def __init__(self, items_by_sku: Dict[str, CartItem]) -> None:
        self.items_by_sku = items_by_sku

    def get_item(self, sku: str) -> Optional[CartItem]:
        return self.items_by_sku.get(sku)


class DiscountRepository:
    def __init__(self, codes: Dict[str, DiscountCode]) -> None:
        self.codes = {k.upper(): v for k, v in codes.items()}

    def get_code(self, code: str) -> Optional[DiscountCode]:
        return self.codes.get(code.upper())


class PaymentGateway:
    def charge(self, amount: Decimal, payment_method: PaymentMethod, user: User) -> PaymentResult:
        amount = money(amount)
        if amount <= Decimal("0.00"):
            return PaymentResult(
                success=True,
                transaction_id=f"free_{uuid4().hex}",
                amount_charged=Decimal("0.00"),
                status="authorized",
            )
        if not payment_method.token:
            return PaymentResult(
                success=False,
                amount_charged=amount,
                status="failed",
                error="Missing payment token",
            )
        if payment_method.metadata.get("force_fail"):
            return PaymentResult(
                success=False,
                amount_charged=amount,
                status="declined",
                error="Payment declined",
            )
        return PaymentResult(
            success=True,
            transaction_id=f"txn_{uuid4().hex}",
            amount_charged=amount,
            status="captured",
        )


